from langchain_openai import ChatOpenAI
from typing_extensions import Annotated, TypedDict

# class to grade the correctness of the answer generated by the RAG system.
#  The grade will be based on the following criteria:
class CorrectnessGrade(TypedDict):

    explanation: Annotated[str, ..., "Explain your reasoning for the score"]
    correct: Annotated[bool, ..., "True if the answer is correct, False otherwise."]

#Grade Prompt
correctness_instructions = """You are a teacher grading a quiz. 
    You will be given a QUESTION, the GROUND TRUTH (correct) ANSWER, and the STUDENT ANSWER. 
    Here is the grade criteria to follow:
    (1) Grade the student answers based ONLY on their factual accuracy relative to 
    the ground truth answer. (2) Ensure that the student answer does not contain any 
    conflicting statements.
    (3) It is OK if the student answer contains more information than the ground truth answer, 
    as long as it is factually accurate relative to the  ground truth answer.

    Correctness:
    A correctness value of True means that the student's answer meets all of the criteria.
    A correctness value of False means that the student's answer does not meet all of the 
    criteria.

    Explain your reasoning in a step-by-step manner to ensure your reasoning and 
    conclusion are correct. Avoid simply stating the correct answer at the outset."""

# Grader LLM
grader_llm = ChatOpenAI(model="gpt-5.4", temperature=0).with_structured_output(
        CorrectnessGrade, method="json_schema", strict=True
        )

def correctness(inputs: dict, outputs: dict, reference_outputs: dict) -> bool:
    """An evaluator for RAG answer accuracy"""

    print(f"outputs **************************** : {outputs}")

    answers = f"""\
                QUESTION: {inputs['question']}
                GROUND TRUTH ANSWER: {reference_outputs['answer']}
                STUDENT ANSWER: {outputs['answers:']}
    """ 
    
    # Run evaluator
    grade = grader_llm.invoke([
        {"role": "system", "content": correctness_instructions},
        {"role": "user", "content": answers}
    ])
    return grade["correct"]

